import React from "react";

const Inflation = () => {
  const inflationData = [
    { month: "Jan", loss: 1200 },
    { month: "Feb", loss: 1500 },
    { month: "Mar", loss: 1800 },
    { month: "Apr", loss: 2100 },
    { month: "May", loss: 2500 },
    { month: "Jun", loss: 2900 }
  ];

  return (
    <div className="page-container">
      <h2>Inflation Loss Report</h2>

      <table className="data-table">
        <thead>
          <tr>
            <th>Month</th>
            <th>Loss Due to Inflation</th>
          </tr>
        </thead>

        <tbody>
          {inflationData.map((item, index) => (
            <tr key={index}>
              <td>{item.month}</td>
              <td>₹{item.loss}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Inflation;
